
class MathUtility:
    history = []
    @staticmethod
    def power(a,b):
        result =  a**b
        MathUtility.history.append((f"{a} raised to {b}",result))
        if(len(MathUtility.history)>5):
            MathUtility.history.pop(0)
        return result
    def subtract(a,b):
        MathUtility.history.append((f"{a} subtracted form {b}",(a-b)))
        if(len(MathUtility.history)>5):
            MathUtility.history.pop(0)
        return (a-b)
    def multiply(a,b):
        MathUtility.history.append((f"{a} multiplied by {b}",(a*b)))
        if(len(MathUtility.history)>5):
            MathUtility.history.pop(0)
        return (a*b)
    def devide(a,b):
        MathUtility.history.append((f"{a} devided by {b}",(a/b)))
        if(len(MathUtility.history)>5):
            MathUtility.history.pop(0)
        try:
            result = a/b
            return result
        except ZeroDivisionError:
            raise ValueError("cannot divide by zero")
    def add(a,b):
        MathUtility.history.append((f"{a} added to {b}",(a+b)))
        if(len(MathUtility.history)>5):
            MathUtility.history.pop(0)
        return (a+b)

a = int(input("enter the first number here: "))
b = int(input("enter the second number here: "))
print("result for addition is : ",MathUtility.add(a,b))
print("result for subrtaction is : ",MathUtility.subtract(a,b))
print("result for multiply is : ",MathUtility.multiply(a,b))
print("result for devide is : ",MathUtility.devide(a,b))
print("result for power is : ",MathUtility.power(a,b))
print(MathUtility.history)




